import openpyxl
wb = openpyxl.load_workbook('test-supply.xlsx')
for sheet_name in wb.sheetnames:
    ws = wb[sheet_name]
    print(f"\n=== {sheet_name} ===")
    print(f"Dimensions: {ws.dimensions}")
    for row in ws.iter_rows(min_row=1, max_row=20, values_only=False):
        vals = []
        for cell in row:
            v = cell.value
            if v is not None:
                vals.append(f"{cell.coordinate}={v}")
        if vals:
            print(" | ".join(vals))
